bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    // Define valid transitions based on state flow
    switch (from) {
        case kDeviceStateUnknown:
            // Can only go to starting state
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            // Can only go to wifi_configuring state
            return to == kDeviceStateWifiConfiguring;

        case kDeviceStateWifiConfiguring:
            // Can go to idle state or directly to fatal_error
            return (to == kDeviceStateIdle) || (to == kDeviceStateFatalError);

        case kDeviceStateIdle:
            // Can go to connecting, listening, or fatal_error
            return (to == kDeviceStateConnecting) || 
                   (to == kDeviceStateListening) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateConnecting:
            // Can go to listening or fatal_error
            return (to == kDeviceStateListening) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateListening:
            // Can go to speaking, upgrading, or fatal_error
            return (to == kDeviceStateSpeaking) || 
                   (to == kDeviceStateUpgrading) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateSpeaking:
            // Can go back to idle or fatal_error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateUpgrading:
            // Can go to activating or fatal_error
            return (to == kDeviceStateActivating) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateActivating:
            // Can go to audio_testing or fatal_error
            return (to == kDeviceStateAudioTesting) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateAudioTesting:
            // Can go back to idle or fatal_error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateFatalError:
            // Can only go to itself (no further transitions)
            return false;

        default:
            // Invalid from state
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    DeviceState old_state = current_state_.load();

    // Check if the transition is valid
    if (!IsValidTransition(old_state, new_state))
    {
        ESP_LOGW(TAG, "Invalid state transition from %s to %s", 
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform the state transition
    current_state_.store(new_state);

    // Notify all registered listeners of the state change
    NotifyStateChange(old_state, new_state);

    ESP_LOGI(TAG, "State transitioned from %s to %s", 
             GetStateName(old_state), GetStateName(new_state));

    return true;
}

void McpServer::AddCommonTools()
{
    // Device status
    AddTool("self.get_status", "Get the current device status including battery level, network status, etc.",
            PropertyList(),
            [this](const PropertyList &properties) -> ReturnValue
            {
                auto &board = Board::GetInstance();
                cJSON *json = cJSON_CreateObject();

                // Battery level
                auto battery_level = board.GetBatteryLevel();
                if (battery_level >= 0)
                {
                    cJSON_AddNumberToObject(json, "battery_level", battery_level);
                }

                // Network status
                auto network = board.GetNetwork();
                if (network)
                {
                    cJSON_AddBoolToObject(json, "network_connected", network->IsConnected());
                }

                // CPU temperature
                auto cpu_temp = board.GetCpuTemperature();
                if (cpu_temp >= 0)
                {
                    cJSON_AddNumberToObject(json, "cpu_temperature", cpu_temp);
                }

                // Memory info
                cJSON_AddNumberToObject(json, "free_heap", esp_get_free_heap_size());
                cJSON_AddNumberToObject(json, "min_free_heap", esp_get_minimum_free_heap_size());

                return json;
            });

    // Audio control
    AddTool("self.set_audio_volume", "Set the audio volume level",
            PropertyList({Property("volume", kPropertyTypeInteger, 50, 0, 100)}),
            [this](const PropertyList &properties) -> ReturnValue
            {
                auto volume = properties["volume"].value<int>();
                auto &board = Board::GetInstance();
                auto audio = board.GetAudio();
                if (audio)
                {
                    audio->SetVolume(volume);
                }
                return true;
            });

    // Screen brightness
    AddTool("self.set_screen_brightness", "Set the screen brightness level",
            PropertyList({Property("brightness", kPropertyTypeInteger, 100, 0, 100)}),
            [this](const PropertyList &properties) -> ReturnValue
            {
                auto brightness = properties["brightness"].value<int>();
                auto &board = Board::GetInstance();
                auto display = board.GetDisplay();
                if (display)
                {
                    display->SetBrightness(brightness);
                }
                return true;
            });

    // Theme control
    AddTool("self.set_theme", "Change the display theme",
            PropertyList({Property("theme", kPropertyTypeString, "default")}),
            [this](const PropertyList &properties) -> ReturnValue
            {
                auto theme_name = properties["theme"].value<std::string>();
                auto &board = Board::GetInstance();
                auto display = board.GetDisplay();
                if (display)
                {
                    // Try to apply the theme
                    if (theme_name == "dark")
                    {
                        display->SetTheme(LvglTheme::kDark);
                    }
                    else if (theme_name == "light")
                    {
                        display->SetTheme(LvglTheme::kLight);
                    }
                    else
                    {
                        display->SetTheme(LvglTheme::kDefault);
                    }
                }
                return true;
            });
}

void McpServer::AddUserOnlyTools()
{
    auto &board = Board::GetInstance();

    // Add tool to get system information
    AddUserOnlyTool("self.get_system_info",
                    "Retrieve comprehensive system information including CPU usage, memory usage, storage information, and network status.",
                    PropertyList(),
                    [&board](const PropertyList &properties) -> ReturnValue
                    {
                        auto system_info = board.GetSystemInfo();
                        return system_info;
                    });

    // Add tool to reboot the device
    AddUserOnlyTool("self.reboot",
                    "Reboot the device immediately. This will cause all running processes to stop and the device to restart.",
                    PropertyList(),
                    [&board](const PropertyList &properties) -> ReturnValue
                    {
                        // Schedule the reboot to happen in the main thread
                        auto &app = Application::GetInstance();
                        app.Schedule([]()
                                     {
                                         board.Reboot();
                                     });
                        return true;
                    });

    // Add tool to upgrade firmware from URL
    AddUserOnlyTool("self.firmware_upgrade",
                    "Upgrade the device firmware from a given URL. This will download and install the new firmware.",
                    PropertyList({Property("url", kPropertyTypeString)}),
                    [&board](const PropertyList &properties) -> ReturnValue
                    {
                        auto url = properties["url"].value<std::string>();
                        // Schedule the firmware upgrade to happen in the main thread
                        auto &app = Application::GetInstance();
                        app.Schedule([url]()
                                     {
                                         board.UpgradeFirmware(url);
                                     });
                        return true;
                    });

    // Add tool to take screenshot
    AddUserOnlyTool("self.take_screenshot",
                    "Capture and retrieve a screenshot of the current screen display.",
                    PropertyList(),
                    [&board](const PropertyList &properties) -> ReturnValue
                    {
                        auto display = board.GetDisplay();
                        if (display)
                        {
                            // Lower the priority to do the screenshot capture
                            TaskPriorityReset priority_reset(1);

                            if (display->TakeScreenshot())
                            {
                                return display->GetScreenshotData();
                            }
                        }
                        return false;
                    });
}

void McpServer::ParseMessage(const cJSON *json)
{
    auto method = cJSON_GetObjectItem(json, "method");
    auto params = cJSON_GetObjectItem(json, "params");
    auto id = cJSON_GetObjectItem(json, "id");

    if (!cJSON_IsString(method))
    {
        ESP_LOGE(TAG, "Invalid method in MCP message");
        return;
    }

    std::string method_str = method->valuestring;

    if (method_str == "initialize")
    {
        // Handle initialize method
        auto capabilities = cJSON_GetObjectItem(json, "params");
        if (capabilities && cJSON_IsObject(capabilities))
        {
            ParseCapabilities(capabilities);
        }

        // Send initialize response
        std::string response = "{\"jsonrpc\":\"2.0\",\"id\":";
        if (id && cJSON_IsNumber(id))
        {
            response += std::to_string(id->valueint);
        }
        else
        {
            response += "null";
        }
        response += ",\"result\":{\"capabilities\":{}}}";
        Application::GetInstance().SendMcpMessage(response);
    }
    else if (method_str == "tools/list")
    {
        // Handle tools/list method
        int request_id = 0;
        if (id && cJSON_IsNumber(id))
        {
            request_id = id->valueint;
        }

        std::string cursor = "";
        bool list_user_only = false;

        if (params && cJSON_IsObject(params))
        {
            auto cursor_item = cJSON_GetObjectItem(params, "cursor");
            if (cursor_item && cJSON_IsString(cursor_item))
            {
                cursor = cursor_item->valuestring;
            }

            auto user_only_item = cJSON_GetObjectItem(params, "listUserOnlyTools");
            if (user_only_item && cJSON_IsBool(user_only_item))
            {
                list_user_only = user_only_item->valueint == 1;
            }
        }

        GetToolsList(request_id, cursor, list_user_only);
    }
    else if (method_str == "tools/call")
    {
        // Handle tools/call method
        int request_id = 0;
        if (id && cJSON_IsNumber(id))
        {
            request_id = id->valueint;
        }

        if (!params || !cJSON_IsObject(params))
        {
            ReplyError(request_id, "Invalid parameters for tools/call");
            return;
        }

        auto tool_name = cJSON_GetObjectItem(params, "name");
        auto tool_arguments = cJSON_GetObjectItem(params, "arguments");

        if (!tool_name || !cJSON_IsString(tool_name))
        {
            ReplyError(request_id, "Missing or invalid tool name");
            return;
        }

        if (!tool_arguments || !cJSON_IsObject(tool_arguments))
        {
            ReplyError(request_id, "Missing or invalid tool arguments");
            return;
        }

        DoToolCall(request_id, tool_name->valuestring, tool_arguments);
    }
    else
    {
        ESP_LOGW(TAG, "Unsupported method: %s", method_str.c_str());
        // For unsupported methods, we don't send a response as per JSON-RPC spec
    }
}

void McpServer::GetToolsList(int id, const std::string &cursor, bool list_user_only_tools)
{
    // Convert cursor to integer for pagination
    int cursor_index = 0;
    if (!cursor.empty()) {
        try {
            cursor_index = std::stoi(cursor);
        } catch (const std::exception&) {
            // If cursor is not a valid number, start from beginning
            cursor_index = 0;
        }
    }

    // Calculate the maximum payload size (512KB limit)
    const size_t MAX_PAYLOAD_SIZE = 512 * 1024;

    // Start building the response
    std::string response = "{\"tools\":[";

    bool first_tool = true;
    int current_index = 0;
    size_t current_payload_size = response.length();

    // Iterate through tools starting from cursor_index
    for (size_t i = cursor_index; i < tools_.size(); ++i) {
        const McpTool* tool = tools_.at(i);

        // Skip user-only tools if not requested
        if (list_user_only_tools && !tool->user_only()) {
            continue;
        }

        // Skip non-user tools if user-only tools are requested
        if (!list_user_only_tools && tool->user_only()) {
            continue;
        }

        // Build tool definition JSON
        std::string tool_json = first_tool ? "" : ",";
        tool_json += "{";
        tool_json += "\"name\":\"" + tool->name() + "\",";
        tool_json += "\"description\":\"" + tool->description() + "\",";
        tool_json += "\"inputSchema\":{";
        tool_json += "\"type\":\"object\",";
        tool_json += "\"properties\":{";

        bool first_property = true;
        const PropertyList& properties = tool->properties();

        for (const auto& property : properties) {
            if (first_property) {
                first_property = false;
            } else {
                tool_json += ",";
            }

            tool_json += "\"" + property.name() + "\":{";
            tool_json += "\"type\":\"" + 
                (property.type() == kPropertyTypeString ? "string" :
                 property.type() == kPropertyTypeInteger ? "integer" :
                 property.type() == kPropertyTypeBoolean ? "boolean" : "unknown") + "\"";

            if (property.has_default_value()) {
                if (property.type() == kPropertyTypeString) {
                    tool_json += ",\"default\":\"" + property.value<std::string>() + "\"";
                } else if (property.type() == kPropertyTypeInteger) {
                    tool_json += ",\"default\":" + std::to_string(property.value<int>());
                } else if (property.type() == kPropertyTypeBoolean) {
                    tool_json += ",\"default\":" + std::string(property.value<bool>() ? "true" : "false");
                }
            }

            if (property.min_value() != 0 || property.max_value() != 0) {
                tool_json += ",\"minimum\":" + std::to_string(property.min_value()) + 
                           ",\"maximum\":" + std::to_string(property.max_value());
            }

            tool_json += "}";
        }

        tool_json += "},";
        tool_json += "\"required\":[";

        bool first_required = true;
        for (const auto& property : properties) {
            if (!property.has_default_value()) {
                if (first_required) {
                    first_required = false;
                } else {
                    tool_json += ",";
                }
                tool_json += "\"" + property.name() + "\"";
            }
        }
        tool_json += "]";
        tool_json += "}}";

        // Check if adding this tool would exceed the payload size limit
        if (current_payload_size + tool_json.length() > MAX_PAYLOAD_SIZE) {
            // Return partial list with cursor for next page
            std::string next_cursor = std::to_string(i);
            std::string final_response = response + "],\"cursor\":\"" + next_cursor + "\"}";
            ReplyResult(id, final_response);
            return;
        }

        response += tool_json;
        current_payload_size += tool_json.length();
        first_tool = false;
        current_index++;
    }

    // Complete the response
    response += "]}";

    // Add cursor if there are more tools
    if (cursor_index + current_index < static_cast<int>(tools_.size())) {
        std::string next_cursor = std::to_string(cursor_index + current_index);
        response.insert(response.length() - 2, ",\"cursor\":\"" + next_cursor + "\"");
    }

    ReplyResult(id, response);
}

void McpServer::DoToolCall(int id, const std::string &tool_name, const cJSON *tool_arguments)
{
    // Find the tool by name
    McpTool *tool = nullptr;
    for (auto t : tools_)
    {
        if (t->name() == tool_name)
        {
            tool = t;
            break;
        }
    }

    if (tool == nullptr)
    {
        ESP_LOGE(TAG, "Tool not found: %s", tool_name.c_str());
        ReplyError(id, "Tool not found: " + tool_name);
        return;
    }

    // Parse arguments
    PropertyList properties;
    if (tool_arguments != nullptr)
    {
        // Convert cJSON object to PropertyList
        for (auto prop : tool->properties())
        {
            auto item = cJSON_GetObjectItem(tool_arguments, prop.name().c_str());
            if (item == nullptr)
            {
                if (prop.required())
                {
                    ESP_LOGE(TAG, "Required argument missing: %s", prop.name().c_str());
                    ReplyError(id, "Required argument missing: " + prop.name());
                    return;
                }
                continue; // Skip optional arguments that are not provided
            }

            try
            {
                switch (prop.type())
                {
                case kPropertyTypeString:
                    if (cJSON_IsString(item))
                    {
                        properties[prop.name()] = std::string(item->valuestring);
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Argument %s should be string", prop.name().c_str());
                        ReplyError(id, "Argument " + prop.name() + " should be string");
                        return;
                    }
                    break;

                case kPropertyTypeInteger:
                    if (cJSON_IsNumber(item))
                    {
                        properties[prop.name()] = (int)item->valuedouble;
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Argument %s should be integer", prop.name().c_str());
                        ReplyError(id, "Argument " + prop.name() + " should be integer");
                        return;
                    }
                    break;

                case kPropertyTypeBoolean:
                    if (cJSON_IsBool(item))
                    {
                        properties[prop.name()] = (bool)item->valueint;
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Argument %s should be boolean", prop.name().c_str());
                        ReplyError(id, "Argument " + prop.name() + " should be boolean");
                        return;
                    }
                    break;

                default:
                    ESP_LOGE(TAG, "Unsupported property type for argument %s", prop.name().c_str());
                    ReplyError(id, "Unsupported property type for argument " + prop.name());
                    return;
                }
            }
            catch (const std::exception &e)
            {
                ESP_LOGE(TAG, "Error parsing argument %s: %s", prop.name().c_str(), e.what());
                ReplyError(id, "Error parsing argument " + prop.name() + ": " + std::string(e.what()));
                return;
            }
        }
    }

    // Validate argument ranges for integers
    for (auto prop : tool->properties())
    {
        if (prop.type() == kPropertyTypeInteger)
        {
            auto it = properties.find(prop.name());
            if (it != properties.end())
            {
                int value = it->second.value<int>();
                if (value < prop.min_value() || value > prop.max_value())
                {
                    ESP_LOGE(TAG, "Argument %s out of range [%d, %d]", prop.name().c_str(), prop.min_value(), prop.max_value());
                    ReplyError(id, "Argument " + prop.name() + " out of range [" + std::to_string(prop.min_value()) + ", " + std::to_string(prop.max_value()) + "]");
                    return;
                }
            }
        }
    }

    // Schedule tool execution on the main thread
    auto &app = Application::GetInstance();
    app.Schedule([this, id, tool, properties]()
                 {
        try {
            auto result = tool->callback()(properties);

            // Handle different return types
            if (std::holds_alternative<bool>(result)) {
                bool b = std::get<bool>(result);
                if (b) {
                    ReplyResult(id, "{}");
                } else {
                    ReplyError(id, "Tool execution failed");
                }
            } else if (std::holds_alternative<cJSON*>(result)) {
                cJSON* json_result = std::get<cJSON*>(result);
                if (json_result) {
                    char* json_string = cJSON_PrintUnformatted(json_result);
                    if (json_string) {
                        std::string payload = "{\"jsonrpc\":\"2.0\",\"id\":";
                        payload += std::to_string(id) + ",\"result\":";
                        payload += json_string;
                        payload += "}";
                        Application::GetInstance().SendMcpMessage(payload);
                        cJSON_Free(json_string);
                    } else {
                        ReplyError(id, "Failed to serialize result");
                    }
                    cJSON_Delete(json_result);
                } else {
                    ReplyError(id, "Tool returned null JSON result");
                }
            } else {
                ReplyError(id, "Unknown result type from tool");
            }
        } catch (const std::exception& e) {
            ESP_LOGE(TAG, "Tool %s threw exception: %s", tool->name().c_str(), e.what());
            ReplyError(id, std::string("Tool error: ") + e.what());
        } catch (...) {
            ESP_LOGE(TAG, "Tool %s threw unknown exception", tool->name().c_str());
            ReplyError(id, "Tool threw unknown exception");
        } });
}

esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.back() != '/')
    {
        url += "/version";
    }
    else
    {
        url += "version";
    }

    auto http = SetupHttp();

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection for version check");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to check version, code: %d", status_code);
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response from version check");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Version check response: %s", response.c_str());

    cJSON *json = cJSON_Parse(response.c_str());
    if (json == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Check for new version
    cJSON *version = cJSON_GetObjectItem(json, "version");
    if (version && cJSON_IsString(version))
    {
        std::string new_version = cJSON_GetStringValue(version);
        if (!new_version.empty())
        {
            auto current_version = esp_app_get_description()->version;
            ESP_LOGI(TAG, "Current version: %s, Available version: %s", current_version, new_version.c_str());

            if (IsNewVersionAvailable(current_version, new_version))
            {
                firmware_url_ = "";
                cJSON *download_url = cJSON_GetObjectItem(json, "download_url");
                if (download_url && cJSON_IsString(download_url))
                {
                    firmware_url_ = cJSON_GetStringValue(download_url);
                }

                if (firmware_url_.empty())
                {
                    ESP_LOGE(TAG, "No download URL provided in version response");
                    cJSON_Delete(json);
                    return ESP_FAIL;
                }

                ESP_LOGI(TAG, "New firmware available at: %s", firmware_url_.c_str());
            }
        }
    }

    // Handle activation challenge
    cJSON *challenge = cJSON_GetObjectItem(json, "challenge");
    if (challenge && cJSON_IsString(challenge))
    {
        activation_challenge_ = cJSON_GetStringValue(challenge);
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Received activation challenge: %s", activation_challenge_.c_str());
    }
    else
    {
        has_activation_challenge_ = false;
    }

    // Handle MQTT configuration
    cJSON *mqtt_config = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_config && cJSON_IsObject(mqtt_config))
    {
        Settings settings("mqtt", true);

        cJSON *server = cJSON_GetObjectItem(mqtt_config, "server");
        if (server && cJSON_IsString(server))
        {
            settings.SetString("server", cJSON_GetStringValue(server));
        }

        cJSON *port = cJSON_GetObjectItem(mqtt_config, "port");
        if (port && cJSON_IsNumber(port))
        {
            settings.SetInt("port", cJSON_GetNumberValue(port));
        }

        cJSON *username = cJSON_GetObjectItem(mqtt_config, "username");
        if (username && cJSON_IsString(username))
        {
            settings.SetString("username", cJSON_GetStringValue(username));
        }

        cJSON *password = cJSON_GetObjectItem(mqtt_config, "password");
        if (password && cJSON_IsString(password))
        {
            settings.SetString("password", cJSON_GetStringValue(password));
        }

        cJSON *topic = cJSON_GetObjectItem(mqtt_config, "topic");
        if (topic && cJSON_IsString(topic))
        {
            settings.SetString("topic", cJSON_GetStringValue(topic));
        }

        settings.Save();
        ESP_LOGI(TAG, "MQTT configuration updated");
    }

    cJSON_Delete(json);
    return ESP_OK;
}

bool Ota::Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> callback) {
    ESP_LOGI(TAG, "Starting firmware upgrade from: %s", firmware_url.c_str());

    // Create HTTP client
    auto& board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto http = network->CreateHttp(0);

    // Set up headers
    auto user_agent = SystemInfo::GetUserAgent();
    http->SetHeader("User-Agent", user_agent);
    http->SetHeader("Accept-Language", Lang::CODE);
    http->SetHeader("Content-Type", "application/octet-stream");

    // Open connection
    if (!http->Open("GET", firmware_url)) {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for firmware download, code=0x%x", last_error);
        return false;
    }

    // Get content length
    size_t content_length = http->GetContentLength();
    if (content_length == 0) {
        ESP_LOGE(TAG, "Failed to get content length for firmware download");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Firmware size: %zu bytes", content_length);

    // Start OTA update
    esp_err_t err = ESP_OK;
    esp_ota_handle_t update_handle = 0;
    const esp_partition_t *update_partition = NULL;

    // Find the next OTA partition
    update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == NULL) {
        ESP_LOGE(TAG, "No OTA partition found");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition label %s at offset 0x%x", 
             update_partition->label, update_partition->address);

    // Begin OTA update
    err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed, error=%s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    // Download and write firmware
    const size_t buffer_size = 4096;
    uint8_t *buffer = new uint8_t[buffer_size];
    if (buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate buffer for firmware download");
        http->Close();
        esp_ota_end(update_handle);
        return false;
    }

    size_t total_downloaded = 0;
    uint32_t last_time = 0;
    size_t last_bytes = 0;
    size_t speed = 0;

    while (total_downloaded < content_length) {
        size_t bytes_to_read = std::min(buffer_size, content_length - total_downloaded);
        int bytes_read = http->Read(buffer, bytes_to_read);

        if (bytes_read <= 0) {
            ESP_LOGE(TAG, "Failed to read firmware data, bytes_read=%d", bytes_read);
            delete[] buffer;
            http->Close();
            esp_ota_end(update_handle);
            return false;
        }

        // Write to OTA partition
        err = esp_ota_write(update_handle, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed, error=%s", esp_err_to_name(err));
            delete[] buffer;
            http->Close();
            esp_ota_end(update_handle);
            return false;
        }

        total_downloaded += bytes_read;

        // Calculate and report progress
        int progress = (int)((total_downloaded * 100) / content_length);

        // Calculate speed every 100ms
        uint32_t current_time = esp_timer_get_time() / 1000; // milliseconds
        if (current_time - last_time >= 100 || total_downloaded == content_length) {
            if (last_time > 0) {
                uint32_t time_diff = current_time - last_time;
                size_t bytes_diff = total_downloaded - last_bytes;
                if (time_diff > 0) {
                    speed = (bytes_diff * 1000) / time_diff; // bytes per second
                }
            }
            last_time = current_time;
            last_bytes = total_downloaded;

            if (callback) {
                callback(progress, speed);
            }
        }
    }

    // Finalize OTA update
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed, error=%s", esp_err_to_name(err));
        delete[] buffer;
        http->Close();
        return false;
    }

    // Set the new OTA partition as the boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed, error=%s", esp_err_to_name(err));
        delete[] buffer;
        http->Close();
        return false;
    }

    delete[] buffer;
    http->Close();

    ESP_LOGI(TAG, "Firmware upgrade completed successfully");
    return true;
}

std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        // Return empty JSON object if no serial number
        return "{}";
    }

    // Create JSON payload with required fields
    cJSON *root = cJSON_CreateObject();
    if (root == NULL)
    {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge
    if (has_activation_challenge_)
    {
        cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());
    }

    // Add timestamp (current time)
    cJSON_AddNumberToObject(root, "timestamp", time(NULL));

    // Generate HMAC-SHA256 signature
    std::string payload_str = cJSON_PrintUnformatted(root);
    if (payload_str.empty())
    {
        cJSON_Delete(root);
        return "{}";
    }

    // Generate signature using HMAC-SHA256
    uint8_t hmac_result[32]; // SHA256 produces 32 bytes
    esp_err_t err = ESP_FAIL;

#ifdef SOC_HMAC_SUPPORTED
    // Use hardware HMAC if supported
    err = esp_hmac_calculate(ESP_HMAC_SHA256, 
                            (const uint8_t*)payload_str.c_str(),
                            payload_str.length(),
                            (const uint8_t*)CONFIG_ACTIVATION_KEY,
                            strlen(CONFIG_ACTIVATION_KEY),
                            hmac_result);
#else
    // Fallback to software implementation or skip signing
    // For now, we'll skip HMAC calculation if hardware support is not available
    ESP_LOGW(TAG, "HMAC hardware support not available, skipping signature");
#endif

    if (err == ESP_OK)
    {
        // Convert HMAC result to hex string
        char hmac_hex[65] = {0}; // 32 bytes * 2 + 1 for null terminator
        for (int i = 0; i < 32; i++)
        {
            sprintf(&hmac_hex[i*2], "%02x", hmac_result[i]);
        }
        cJSON_AddStringToObject(root, "signature", hmac_hex);
    }
    else
    {
        ESP_LOGW(TAG, "Failed to calculate HMAC, skipping signature");
    }

    // Clean up and return JSON string
    std::string result = cJSON_PrintUnformatted(root);
    cJSON_Delete(root);

    return result;
}

esp_err_t Ota::Activate()
{
    if (!has_serial_number_)
    {
        ESP_LOGI(TAG, "No serial number available, skipping activation");
        return ESP_OK;
    }

    if (!has_activation_challenge_)
    {
        ESP_LOGE(TAG, "No activation challenge available");
        return ESP_ERR_INVALID_STATE;
    }

    std::string url = GetCheckVersionUrl();
    if (url.length() < 10)
    {
        ESP_LOGE(TAG, "Activation URL is not properly set");
        return ESP_ERR_INVALID_ARG;
    }

    // Append "/activate" to the base URL for activation endpoint
    if (url.back() != '/')
    {
        url += '/';
    }
    url += "activate";

    auto http = SetupHttp();

    // Set up the activation payload
    std::string payload = GetActivationPayload();
    http->SetContent(std::move(payload));

    // Set Content-Type header for JSON payload
    http->SetHeader("Content-Type", "application/json");

    if (!http->Open("POST", url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to activate, status code: %d", status_code);
        return status_code;
    }

    std::string response = http->ReadAll();
    http->Close();

    // Parse the JSON response to check activation result
    cJSON *root = cJSON_Parse(response.c_str());
    if (root == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse activation response JSON");
        return ESP_ERR_INVALID_RESPONSE;
    }

    cJSON *success = cJSON_GetObjectItem(root, "success");
    if (cJSON_IsBool(success))
    {
        if (!cJSON_IsTrue(success))
        {
            cJSON *error = cJSON_GetObjectItem(root, "error");
            if (cJSON_IsString(error))
            {
                ESP_LOGE(TAG, "Activation failed: %s", error->valuestring);
            }
            else
            {
                ESP_LOGE(TAG, "Activation failed with unknown error");
            }
            cJSON_Delete(root);
            return ESP_FAIL;
        }
    }
    else
    {
        ESP_LOGE(TAG, "Invalid activation response format");
        cJSON_Delete(root);
        return ESP_ERR_INVALID_RESPONSE;
    }

    cJSON_Delete(root);

    ESP_LOGI(TAG, "Activation successful");
    return ESP_OK;
}

esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    // Get initial task statistics
    TaskStatus_t *pxTaskStatusArray;
    UBaseType_t uxArraySize;
    volatile UBaseType_t uxHigherPriorityReadyTasks;

    // Get the number of tasks
    uxArraySize = uxTaskGetNumberOfTasks();

    // Allocate memory for task status array
    pxTaskStatusArray = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * uxArraySize);
    if (pxTaskStatusArray == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task status array");
        return ESP_FAIL;
    }

    // Get current task status
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &uxHigherPriorityReadyTasks);

    // Store initial run time counters
    uint32_t *ulPreviousTotalRunTime = (uint32_t *)malloc(sizeof(uint32_t) * uxArraySize);
    if (ulPreviousTotalRunTime == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for previous run time");
        free(pxTaskStatusArray);
        return ESP_FAIL;
    }

    // Initialize previous run times
    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        ulPreviousTotalRunTime[x] = pxTaskStatusArray[x].ulRunTimeCounter;
    }

    // Wait for the specified time interval
    vTaskDelay(xTicksToWait);

    // Get updated task status
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &uxHigherPriorityReadyTasks);

    // Calculate CPU usage for each task
    char buffer[1000];
    int pos = snprintf(buffer, sizeof(buffer), "Task CPU Usage:\n");

    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        uint32_t ulTotalRunTime = pxTaskStatusArray[x].ulRunTimeCounter - ulPreviousTotalRunTime[x];
        uint32_t ulTotalTime = xTicksToWait * configTICK_RATE_HZ; // Total time in ticks

        // Calculate percentage (avoid division by zero)
        uint32_t ulPercentage = 0;
        if (ulTotalTime > 0) {
            ulPercentage = (ulTotalRunTime * 100) / ulTotalTime;
        }

        // Format task information
        pos += snprintf(buffer + pos, sizeof(buffer) - pos, 
                       "%s: %lu%% (%lu/%lu)\n", 
                       pxTaskStatusArray[x].pcTaskName,
                       ulPercentage,
                       ulTotalRunTime,
                       ulTotalTime);
    }

    ESP_LOGI(TAG, "%s", buffer);

    // Free allocated memory
    free(pxTaskStatusArray);
    free(ulPreviousTotalRunTime);

    return ESP_OK;
}

void AudioService::Initialize(AudioCodec *codec)
{
    codec_ = codec;

    // Initialize Opus encoder and decoder
    opus_encoder_ = std::make_unique<OpusEncoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);
    opus_decoder_ = std::make_unique<OpusDecoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);

    // Configure resamplers
    input_resampler_.Configure(16000, codec_->input_sample_rate());
    output_resampler_.Configure(codec_->output_sample_rate(), codec_->output_sample_rate());

    // Initialize audio processor based on configuration
#if CONFIG_USE_AUDIO_PROCESSOR
    audio_processor_ = std::make_unique<AfeAudioProcessor>();
#else
    audio_processor_ = std::make_unique<NoAudioProcessor>();
#endif

    // Create audio power timer
    const esp_timer_create_args_t audio_power_timer_args = {
        .callback = [](void *arg) {
            AudioService* service = static_cast<AudioService*>(arg);
            service->CheckAndUpdateAudioPowerState();
        },
        .name = "audio_power",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK
    };

    esp_timer_create(&audio_power_timer_args, &audio_power_timer_);

    // Initialize timestamps
    timestamp_queue_.clear();

    // Initialize statistics
    debug_statistics_ = {};
}

void AudioService::Start()
{
    // Clear all event flags
    xEventGroupClearBits(event_group_, AS_EVENT_AUDIO_TESTING_RUNNING | 
                                    AS_EVENT_WAKE_WORD_RUNNING | 
                                    AS_EVENT_AUDIO_PROCESSOR_RUNNING);

    // Start the periodic audio power timer
    esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);

    // Create audio input task
    BaseType_t ret = xTaskCreatePinnedToCore(
        [](void *arg) {
            AudioService *service = static_cast<AudioService*>(arg);
            service->AudioInputTask();
        },
        "audio_input_task",
        4096,
        this,
        10,  // Priority
        nullptr,
        0    // Core 0
    );

    if (ret != pdPASS) {
        ESP_LOGE(TAG, "Failed to create audio input task");
    }

    // Create audio output task
    ret = xTaskCreatePinnedToCore(
        [](void *arg) {
            AudioService *service = static_cast<AudioService*>(arg);
            service->AudioOutputTask();
        },
        "audio_output_task",
        4096,
        this,
        10,  // Priority
        nullptr,
        0    // Core 0
    );

    if (ret != pdPASS) {
        ESP_LOGE(TAG, "Failed to create audio output task");
    }

    // Create Opus codec task
    ret = xTaskCreatePinnedToCore(
        [](void *arg) {
            AudioService *service = static_cast<AudioService*>(arg);
            service->OpusCodecTask();
        },
        "opus_codec_task",
        4096,
        this,
        10,  // Priority
        nullptr,
        0    // Core 0
    );

    if (ret != pdPASS) {
        ESP_LOGE(TAG, "Failed to create Opus codec task");
    }
}

bool AudioService::ReadAudioData(std::vector<int16_t> &data, int sample_rate, int samples)
{
    // Read raw audio data from the codec
    std::vector<int16_t> raw_data(samples * codec_->input_channels());

    if (!codec_->InputData(raw_data.data(), samples * codec_->input_channels()))
    {
        return false;
    }

    // Store the last input time for power management
    last_input_time_ = std::chrono::steady_clock::now();

    // If we need to resample or convert channels, do it here
    if (codec_->input_sample_rate() != sample_rate)
    {
        // Resample the data
        int target_samples = input_resampler_.GetOutputSamples(raw_data.size());
        data.resize(target_samples);
        input_resampler_.Process(raw_data.data(), raw_data.size(), data.data());
    }
    else
    {
        data = std::move(raw_data);
    }

    // Update debug statistics
    debug_statistics_.input_count++;

    return true;
}

void AudioService::AudioInputTask()
{
    while (true)
    {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);
        audio_queue_cv_.wait(lock, [this]()
                             { return service_stopped_ || 
                                     (xEventGroupGetBits(event_group_) & (AS_EVENT_AUDIO_TESTING_RUNNING | 
                                                                        AS_EVENT_WAKE_WORD_RUNNING | 
                                                                        AS_EVENT_AUDIO_PROCESSOR_RUNNING)); });

        if (service_stopped_)
        {
            break;
        }

        // Check which processing modes are active
        EventBits_t bits = xEventGroupGetBits(event_group_);
        bool is_testing = (bits & AS_EVENT_AUDIO_TESTING_RUNNING) != 0;
        bool is_wake_word = (bits & AS_EVENT_WAKE_WORD_RUNNING) != 0;
        bool is_audio_processor = (bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING) != 0;

        lock.unlock();

        // Prepare audio buffer
        std::vector<int16_t> audio_data;
        int sample_rate = codec_->input_sample_rate();
        int channels = codec_->input_channels();
        int samples_per_frame = (OPUS_FRAME_DURATION_MS * sample_rate) / 1000;
        int total_samples = samples_per_frame * channels;

        // Read audio data
        if (!ReadAudioData(audio_data, sample_rate, samples_per_frame))
        {
            ESP_LOGE(TAG, "Failed to read audio data");
            continue;
        }

        // Process based on active modes
        if (is_testing)
        {
            // For testing, encode directly to testing queue
            auto task = std::make_unique<AudioTask>();
            task->type = kAudioTaskTypeEncodeToTestingQueue;
            task->pcm = std::move(audio_data);

            std::lock_guard<std::mutex> lock(audio_queue_mutex_);
            if (audio_encode_queue_.size() < MAX_ENCODE_TASKS_IN_QUEUE)
            {
                audio_encode_queue_.push_back(std::move(task));
                audio_queue_cv_.notify_all();
            }
        }
        else if (is_wake_word)
        {
            // For wake word detection, pass to wake word processor
            if (wake_word_)
            {
                wake_word_->ProcessAudioData(audio_data);
            }
        }
        else if (is_audio_processor)
        {
            // For general audio processing, pass to audio processor
            if (audio_processor_)
            {
                audio_processor_->ProcessAudioData(std::move(audio_data));
            }
        }
        else
        {
            // Default case - just pass through for encoding
            auto task = std::make_unique<AudioTask>();
            task->type = kAudioTaskTypeEncodeToSendQueue;
            task->pcm = std::move(audio_data);

            std::lock_guard<std::mutex> lock(audio_queue_mutex_);
            if (audio_encode_queue_.size() < MAX_ENCODE_TASKS_IN_QUEUE)
            {
                audio_encode_queue_.push_back(std::move(task));
                audio_queue_cv_.notify_all();
            }
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(pdMS_TO_TICKS(1));
    }

    ESP_LOGW(TAG, "Audio input task stopped");
}

void AudioService::AudioOutputTask()
{
    while (true)
    {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);
        audio_queue_cv_.wait(lock, [this]()
                             { return service_stopped_ || !audio_playback_queue_.empty(); });

        if (service_stopped_)
        {
            break;
        }

        if (!audio_playback_queue_.empty())
        {
            auto task = std::move(audio_playback_queue_.front());
            audio_playback_queue_.pop_front();
            lock.unlock();

            // Enable audio output if not already enabled
            if (!codec_->output_enabled())
            {
                esp_timer_stop(audio_power_timer_);
                esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
                codec_->EnableOutput(true);
            }

            // Send audio data to codec
            if (codec_->output_channels() == 2)
            {
                // For stereo output, we need to interleave the data
                auto interleaved_data = std::vector<int16_t>(task->pcm.size() * 2);
                for (size_t i = 0; i < task->pcm.size(); ++i)
                {
                    interleaved_data[i * 2] = task->pcm[i];     // Left channel
                    interleaved_data[i * 2 + 1] = task->pcm[i]; // Right channel (mono to stereo)
                }
                codec_->OutputData(interleaved_data);
            }
            else
            {
                // For mono output
                codec_->OutputData(task->pcm);
            }

            // Update last output time
            last_output_time_ = std::chrono::steady_clock::now();

            // Record timestamp for AEC if needed
            if (task->timestamp != 0)
            {
                // This would typically be used for server-side AEC
                // For now, we just log it
                ESP_LOGD(TAG, "Playback timestamp: %ld", task->timestamp);
            }

            debug_statistics_.playback_count++;

            // Notify about available playback slots
            lock.lock();
            audio_queue_cv_.notify_all();
        }
    }

    ESP_LOGW(TAG, "Audio output task stopped");
}

void AudioService::OpusCodecTask()
{
    while (true)
    {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);
        audio_queue_cv_.wait(lock, [this]()
                             { return !audio_encode_queue_.empty() || !audio_decode_queue_.empty() || service_stopped_; });

        if (service_stopped_)
        {
            break;
        }

        // Process encode queue
        while (!audio_encode_queue_.empty())
        {
            auto task = std::move(audio_encode_queue_.front());
            audio_encode_queue_.pop_front();
            lock.unlock();

            switch (task->type)
            {
                case kAudioTaskTypeEncodeToSendQueue:
                {
                    // Encode PCM to Opus
                    auto encoded_data = opus_encoder_->Encode(task->pcm);
                    if (!encoded_data.empty())
                    {
                        auto packet = std::make_unique<AudioStreamPacket>();
                        packet->payload = std::move(encoded_data);
                        packet->sample_rate = 16000;
                        packet->frame_duration = OPUS_FRAME_DURATION_MS;

                        // Push to send queue
                        std::lock_guard<std::mutex> send_lock(audio_queue_mutex_);
                        if (audio_send_queue_.size() < MAX_SEND_PACKETS_IN_QUEUE)
                        {
                            audio_send_queue_.push_back(std::move(packet));
                            audio_queue_cv_.notify_all();
                        }
                        else
                        {
                            ESP_LOGW(TAG, "Send queue is full, dropping packet");
                        }
                    }
                    break;
                }
                case kAudioTaskTypeEncodeToTestingQueue:
                {
                    // For testing, just store the raw PCM data
                    std::lock_guard<std::mutex> test_lock(audio_queue_mutex_);
                    if (audio_testing_queue_.size() < AUDIO_TESTING_MAX_DURATION_MS / OPUS_FRAME_DURATION_MS)
                    {
                        audio_testing_queue_.push_back(std::move(task));
                        audio_queue_cv_.notify_all();
                    }
                    else
                    {
                        ESP_LOGW(TAG, "Audio testing queue is full, dropping data");
                    }
                    break;
                }
            }

            lock.lock();
        }

        // Process decode queue
        while (!audio_decode_queue_.empty())
        {
            auto packet = std::move(audio_decode_queue_.front());
            audio_decode_queue_.pop_front();
            lock.unlock();

            // Decode Opus to PCM
            auto decoded_pcm = opus_decoder_->Decode(packet->payload);
            if (!decoded_pcm.empty())
            {
                // Resample if needed
                if (output_resampler_.GetInputSampleRate() != codec_->output_sample_rate())
                {
                    auto resampled_pcm = std::vector<int16_t>(output_resampler_.GetOutputSamples(decoded_pcm.size()));
                    output_resampler_.Process(decoded_pcm.data(), decoded_pcm.size(), resampled_pcm.data());
                    decoded_pcm = std::move(resampled_pcm);
                }

                // Push to playback queue
                auto playback_task = std::make_unique<AudioTask>();
                playback_task->type = kAudioTaskTypePlayback;
                playback_task->pcm = std::move(decoded_pcm);
                playback_task->timestamp = packet->timestamp;

                std::lock_guard<std::mutex> play_lock(audio_queue_mutex_);
                if (audio_playback_queue_.size() < MAX_PLAYBACK_TASKS_IN_QUEUE)
                {
                    audio_playback_queue_.push_back(std::move(playback_task));
                    audio_queue_cv_.notify_all();
                }
                else
                {
                    ESP_LOGW(TAG, "Playback queue is full, dropping audio data");
                }
            }

            lock.lock();
        }

        // Check if there's more work to do
        if (audio_encode_queue_.empty() && audio_decode_queue_.empty())
        {
            lock.unlock();
        }
    }

    ESP_LOGW(TAG, "Opus codec task stopped");
}

void AudioService::PushTaskToEncodeQueue(AudioTaskType type, std::vector<int16_t> &&pcm)
{
    std::unique_lock<std::mutex> lock(audio_queue_mutex_);

    // Wait if the queue is full
    while (audio_encode_queue_.size() >= MAX_ENCODE_TASKS_IN_QUEUE)
    {
        audio_queue_cv_.wait(lock, [this]()
                             { return audio_encode_queue_.size() < MAX_ENCODE_TASKS_IN_QUEUE; });
    }

    // Create audio task
    auto task = std::make_unique<AudioTask>();
    task->type = type;
    task->pcm = std::move(pcm);

    // Set timestamp if needed
    if (type == kAudioTaskTypeEncodeToSendQueue && !timestamp_queue_.empty())
    {
        task->timestamp = timestamp_queue_.front();
        timestamp_queue_.pop_front();
    }
    else
    {
        task->timestamp = 0;
    }

    // Add to queue
    audio_encode_queue_.push_back(std::move(task));
    audio_queue_cv_.notify_all();
}

void AudioService::EnableWakeWordDetection(bool enable)
{
    ESP_LOGD(TAG, "%s wake word detection", enable ? "Enabling" : "Disabling");

    if (enable)
    {
        if (!wake_word_)
        {
            ESP_LOGE(TAG, "Wake word detection cannot be enabled without a wake word model");
            return;
        }

        /* We should make sure no audio is playing */
        ResetDecoder();

        /* Initialize wake word if needed */
        if (!wake_word_initialized_)
        {
            wake_word_->Initialize(models_list_);
            wake_word_initialized_ = true;
        }

        wake_word_->Start();
        xEventGroupSetBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    }
    else
    {
        if (wake_word_)
        {
            wake_word_->Stop();
        }
        xEventGroupClearBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    }
}

