void AudioService::SetModelsList(srmodel_list_t *models_list)
{
    models_list_ = models_list;

    if (models_list == nullptr || models_list->count == 0) {
        return;
    }

    // Check if we have custom wake word models
    bool has_custom_model = false;
    for (int i = 0; i < models_list->count; i++) {
        if (strncmp(models_list->models[i].name, "custom_", 7) == 0) {
            has_custom_model = true;
            break;
        }
    }

#if CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4
    // For ESP32-S3 and ESP32-P4, use AFE wake word engine
    if (has_custom_model) {
        wake_word_ = std::make_unique<CustomWakeWord>();
    } else {
        wake_word_ = std::make_unique<AfeWakeWord>();
    }
#else
    // For other targets, use ESP wake word engine
    wake_word_ = std::make_unique<EspWakeWord>();
#endif

    // Register wake word detection callback
    if (wake_word_) {
        wake_word_->OnWakeWordDetected([this](const std::string& wake_word) {
            if (callbacks_.on_wake_word_detected) {
                callbacks_.on_wake_word_detected(wake_word);
            }
        });
    }
}

Es8388AudioCodec::Es8388AudioCodec(void* i2c_master_handle, i2c_port_t i2c_port, int input_sample_rate, int output_sample_rate,
    gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din, gpio_num_t pa_pin, uint8_t addr, bool input_reference)
    : AudioCodec(input_sample_rate, output_sample_rate, 2, 2), // Assuming 2 channels for both input and output
      input_reference_(input_reference),
      pa_pin_(pa_pin)
{
    // Initialize I2C control interface
    i2c_ctrl_if_config_t i2c_ctrl_if_cfg = {
        .dev_addr = addr,
        .i2c_port = i2c_port,
        .i2c_master_handle = i2c_master_handle,
        .ctrl_func = NULL,
    };

    ctrl_if_ = audio_codec_new_i2c_ctrl_if(&i2c_ctrl_if_cfg);
    if (!ctrl_if_) {
        ESP_LOGE(TAG, "Failed to create I2C control interface");
        return;
    }

    // Initialize codec interface
    es8388_codec_cfg_t es8388_cfg = {
        .ctrl_if = ctrl_if_,
        .gpio_if = NULL,
        .data_if = NULL,
    };

    codec_if_ = audio_codec_new_es8388_codec(&es8388_cfg);
    if (!codec_if_) {
        ESP_LOGE(TAG, "Failed to create ES8388 codec interface");
        return;
    }

    // Initialize GPIO interface
    gpio_if_config_t gpio_if_cfg = {
        .gpio_intr_handle = NULL,
        .gpio_intr_priority = 0,
    };

    gpio_if_ = audio_codec_new_gpio_if(&gpio_if_cfg);
    if (!gpio_if_) {
        ESP_LOGE(TAG, "Failed to create GPIO interface");
        return;
    }

    // Initialize data interface for input
    i2s_data_if_config_t i2s_data_if_cfg = {
        .type = AUDIO_CODEC_DATA_IF_I2S,
        .i2s_config = {
            .port = I2S_NUM_0,
            .mclk = mclk,
            .bclk = bclk,
            .ws = ws,
            .dout = dout,
            .din = din,
            .mclk_multiple = I2S_MCLK_MULTIPLE_256,
            .data_bit_width = I2S_DATA_BIT_WIDTH_16BIT,
            .slot_bit_width = I2S_SLOT_BIT_WIDTH_AUTO,
            .slot_mode = I2S_SLOT_MODE_STEREO,
            .slot_mask = I2S_STD_SLOT_BOTH,
            .ws_width = I2S_DATA_BIT_WIDTH_16BIT,
            .ws_pol = false,
            .bit_shift = true,
            .left_align = true,
            .big_endian = false,
            .bit_order_lsb = false,
        },
    };

    data_if_ = audio_codec_new_i2s_data_if(&i2s_data_if_cfg);
    if (!data_if_) {
        ESP_LOGE(TAG, "Failed to create I2S data interface");
        return;
    }

    // Initialize input device
    esp_codec_dev_cfg_t input_dev_cfg = {
        .dev_type = ESP_CODEC_DEV_TYPE_IN,
        .codec_if = codec_if_,
        .data_if = data_if_,
        .gpio_if = gpio_if_,
        .task_prio = 10,
        .task_stack = 2048,
        .event_queue_size = 10,
        .buffer_size = 2048,
    };

    ESP_ERROR_CHECK(esp_codec_dev_new(&input_dev_cfg, &input_dev_));
    if (!input_dev_) {
        ESP_LOGE(TAG, "Failed to create input device");
        return;
    }

    // Initialize output device
    esp_codec_dev_cfg_t output_dev_cfg = {
        .dev_type = ESP_CODEC_DEV_TYPE_OUT,
        .codec_if = codec_if_,
        .data_if = data_if_,
        .gpio_if = gpio_if_,
        .task_prio = 10,
        .task_stack = 2048,
        .event_queue_size = 10,
        .buffer_size = 2048,
    };

    ESP_ERROR_CHECK(esp_codec_dev_new(&output_dev_cfg, &output_dev_));
    if (!output_dev_) {
        ESP_LOGE(TAG, "Failed to create output device");
        return;
    }

    // Initialize codec
    ESP_ERROR_CHECK(audio_codec_init(codec_if_));

    // Configure codec registers for proper operation
    // Set default volume levels and configurations
    uint8_t reg_val = 0x00;
    ctrl_if_->write_reg(ctrl_if_, 0x00, 1, &reg_val, 1); // Reset register

    // Configure analog section
    reg_val = 0x00;
    ctrl_if_->write_reg(ctrl_if_, 0x01, 1, &reg_val, 1); // Power down some blocks

    // Configure ADC and DAC
    reg_val = 0x00;
    ctrl_if_->write_reg(ctrl_if_, 0x02, 1, &reg_val, 1); // ADC control

    reg_val = 0x00;
    ctrl_if_->write_reg(ctrl_if_, 0x03, 1, &reg_val, 1); // DAC control

    // Configure headphone output
    reg_val = 0x00;
    ctrl_if_->write_reg(ctrl_if_, 0x04, 1, &reg_val, 1); // Headphone control

    // Configure speaker output
    reg_val = 0x00;
    ctrl_if_->write_reg(ctrl_if_, 0x05, 1, &reg_val, 1); // Speaker control

    // Set default volume to 0dB
    reg_val = 30; // 0dB
    uint8_t regs[] = {46, 47, 48, 49}; // HP_LVOL, HP_RVOL, SPK_LVOL, SPK_RVOL
    for (uint8_t reg : regs) {
        ctrl_if_->write_reg(ctrl_if_, reg, 1, &reg_val, 1);
    }

    ESP_LOGI(TAG, "ES8388 Audio Codec initialized successfully");
}

void Es8388AudioCodec::CreateDuplexChannels(gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din)
{
    // Configure I2S pin configurations
    i2s_pin_config_t i2s_pins = {
        .bck_io_num = bclk,
        .ws_io_num = ws,
        .data_out_num = dout,
        .data_in_num = din,
    };

    // Configure I2S configuration
    i2s_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = input_sample_rate_,  // Use input sample rate as base
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = (i2s_comm_format_t)(I2S_COMM_FORMAT_I2S | I2S_COMM_FORMAT_I2S_MSB),
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0,
        .mclk_multiple = I2S_MCLK_MULT_256,
        .lclk_multiple = I2S_LCLK_MULT_32,
        .bits_per_frame = 32,
    };

    // Install and start I2S driver
    ESP_ERROR_CHECK(i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL));

    // Set up I2S pins
    ESP_ERROR_CHECK(i2s_set_pin(I2S_NUM_0, &i2s_pins));

    // Initialize I2S handles
    rx_handle_ = i2s_get_ringbuf_handle(I2S_NUM_0, &rx_ringbuf);
    tx_handle_ = i2s_get_ringbuf_handle(I2S_NUM_0, &tx_ringbuf);
}

void Es8388AudioCodec::EnableInput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == input_enabled_)
    {
        return;
    }

    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = input_channels_,
            .channel_mask = 0,
            .sample_rate = (uint32_t)input_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(input_dev_, &fs));

        // Set input gain - either fixed value or adjustable
        if (input_reference_)
        {
            // For reference input (stereo), apply fixed gain
            uint8_t reg_val = 24; // Default gain value
            ctrl_if_->write_reg(ctrl_if_, 20, 1, &reg_val, 1); // ADC L Gain
            ctrl_if_->write_reg(ctrl_if_, 21, 1, &reg_val, 1); // ADC R Gain
        }
        else
        {
            // For single channel input, use adjustable gain
            uint8_t reg_val = (uint8_t)input_gain_; // Use configured input gain
            ctrl_if_->write_reg(ctrl_if_, 20, 1, &reg_val, 1); // ADC L Gain
            ctrl_if_->write_reg(ctrl_if_, 21, 1, &reg_val, 1); // ADC R Gain
        }
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(input_dev_));
    }

    AudioCodec::EnableInput(enable);
}

void Es8388AudioCodec::EnableOutput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == output_enabled_)
    {
        return;
    }

    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = 2, // Stereo output
            .channel_mask = ESP_CODEC_DEV_MAKE_CHANNEL_MASK(0) | ESP_CODEC_DEV_MAKE_CHANNEL_MASK(1),
            .sample_rate = (uint32_t)output_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(output_dev_, &fs));
        ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, output_volume_));

        // Enable PA pin if configured
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_set_direction(pa_pin_, GPIO_MODE_OUTPUT);
            gpio_set_level(pa_pin_, 1); // Enable amplifier
        }
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(output_dev_));

        // Disable PA pin if configured
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_set_level(pa_pin_, 0); // Disable amplifier
        }
    }

    AudioCodec::EnableOutput(enable);
}

AudioDebugger::AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, 0);
    if (udp_sockfd_ < 0)
    {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(CONFIG_AUDIO_DEBUG_UDP_PORT);

    // Parse IP address from CONFIG_AUDIO_DEBUG_UDP_SERVER
    if (inet_aton(CONFIG_AUDIO_DEBUG_UDP_SERVER, &udp_server_addr_.sin_addr) == 0)
    {
        ESP_LOGE(TAG, "Invalid IP address: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "Audio debugger initialized with server %s:%d", 
             CONFIG_AUDIO_DEBUG_UDP_SERVER, CONFIG_AUDIO_DEBUG_UDP_PORT);
#endif
}

bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    if (codec == nullptr || models_list == nullptr) {
        ESP_LOGE(TAG, "Invalid parameters for initialization");
        return false;
    }

    // Initialize the audio codec
    if (codec->Initialize() != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize audio codec");
        return false;
    }

    // Load wake word models
    models_ = esp_srmodel_init(models_list);
    if (models_ == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize wake word models");
        return false;
    }

    // Get AFE interface
    afe_iface_ = esp_afe_create_interface();
    if (afe_iface_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create AFE interface");
        esp_srmodel_deinit(models_);
        models_ = nullptr;
        return false;
    }

    // Configure AFE with model settings
    afe_config_t afe_config = {
        .sample_rate = 16000,
        .channel_num = 1,
        .afe_model = models_,
        .afe_mode = AFE_MODE_WAKEWORD,
        .aec_enable = true,
        .agc_enable = true,
        .vad_enable = true,
    };

    // Create AFE data structure
    afe_data_ = afe_iface_->create(&afe_config);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create AFE data");
        esp_srmodel_deinit(models_);
        models_ = nullptr;
        afe_iface_ = nullptr;
        return false;
    }

    // Set wake words
    wake_words_.clear();
    for (int i = 0; i < models_list->model_num; i++) {
        wake_words_.push_back(models_list->model[i].name);
    }

    // Start the audio detection task
    const size_t task_stack_size = 4096 * 2;
    const uint32_t task_priority = 5;

    BaseType_t result = xTaskCreate(
        [](void *arg) {
            auto* self = static_cast<AfeWakeWord*>(arg);
            self->AudioDetectionTask();
        },
        "afe_wake_word_task",
        task_stack_size,
        this,
        task_priority,
        nullptr
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        afe_iface_->destroy(afe_data_);
        afe_data_ = nullptr;
        esp_srmodel_deinit(models_);
        models_ = nullptr;
        afe_iface_ = nullptr;
        return false;
    }

    ESP_LOGI(TAG, "AFE wake word initialization completed successfully");
    return true;
}

void AfeWakeWord::AudioDetectionTask()
{
    while (true)
    {
        // Wait for detection to be started
        EventBits_t bits = xEventGroupWaitBits(event_group_, DETECTION_RUNNING_EVENT, pdFALSE, pdFALSE, portMAX_DELAY);

        // Check if detection is running
        if (bits & DETECTION_RUNNING_EVENT)
        {
            // Process audio data for wake word detection
            if (afe_data_ != nullptr && afe_iface_ != nullptr)
            {
                // Get detection result
                int detection_result = afe_iface_->detect(afe_data_);

                // Check if wake word was detected
                if (detection_result >= 0)
                {
                    // Stop detection
                    xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);

                    // Get the detected wake word
                    std::string detected_word = wake_words_[detection_result];

                    // Store the audio data for this wake word
                    StoreWakeWordData(nullptr, 0); // This will trigger the storage logic

                    // Trigger the callback
                    if (wake_word_detected_callback_)
                    {
                        wake_word_detected_callback_(detected_word);
                    }

                    // Encode the stored wake word data
                    EncodeWakeWordData();
                }
            }
        }

        // Small delay to prevent busy waiting
        vTaskDelay(10 / portTICK_PERIOD_MS);
    }
}

void AfeWakeWord::EncodeWakeWordData()
{
    // Create the encoding task if it doesn't exist
    if (wake_word_encode_task_stack_ == nullptr)
    {
        // Allocate stack space in PSRAM for the encoding task
        wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(
            4096 * sizeof(StackType_t), MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
        if (wake_word_encode_task_stack_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate stack for wake word encode task");
            return;
        }

        // Allocate buffer space in PSRAM for the encoding task
        wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(
            sizeof(StaticTask_t), MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
        if (wake_word_encode_task_buffer_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate buffer for wake word encode task");
            heap_caps_free(wake_word_encode_task_stack_);
            wake_word_encode_task_stack_ = nullptr;
            return;
        }

        // Create the encoding task with high priority and running on core 1
        xTaskCreateStatic([](void *arg)
                          {
                              auto this_ = (AfeWakeWord*)arg;
                              this_->EncodeWakeWordTask();
                          },
                          "wake_word_encode",
                          4096,
                          this,
                          5,  // Higher priority than detection task
                          wake_word_encode_task_stack_,
                          wake_word_encode_task_buffer_);
    }
}

void AfeWakeWord::EncodeWakeWordTask()
{
    // Initialize Opus encoder
    OpusEncoder *encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
    if (encoder == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create Opus encoder");
        return;
    }

    // Set encoder parameters for low complexity and fast encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));  // Lowest complexity
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000)); // 24 kbps bitrate

    // Buffer for encoded data
    std::vector<uint8_t> encode_buffer(1024); // 1KB buffer for encoded data

    ESP_LOGI(TAG, "Wake word encode task started");

    while (true)
    {
        // Wait for PCM data to be available
        std::unique_lock<std::mutex> lock(wake_word_mutex_);
        wake_word_cv_.wait(lock, [this]()
                           { 
                               return !wake_word_pcm_.empty(); 
                           });

        // Process all available PCM data
        while (!wake_word_pcm_.empty())
        {
            // Get the oldest PCM data
            auto pcm_data = wake_word_pcm_.front();
            wake_word_pcm_.pop_front();

            lock.unlock(); // Release lock while doing encoding

            // Encode the PCM data to Opus
            int encoded_size = opus_encode(encoder, pcm_data.data(), 
                                         pcm_data.size(), 
                                         encode_buffer.data(), 
                                         encode_buffer.size());

            if (encoded_size > 0)
            {
                // Store encoded data in thread-safe buffer
                std::unique_lock<std::mutex> encode_lock(wake_word_mutex_);
                wake_word_opus_.emplace_back(std::vector<uint8_t>(encode_buffer.begin(), 
                                                                 encode_buffer.begin() + encoded_size));
                encode_lock.unlock();

                // Signal that we have new encoded data
                wake_word_cv_.notify_one();
            }

            lock.lock(); // Reacquire lock for next iteration
        }

        // Check if there are more data to process
        if (wake_word_pcm_.empty())
        {
            // Notify that processing is complete
            wake_word_cv_.notify_one();
        }
    }

    // Cleanup
    opus_encoder_destroy(encoder);
}

void CustomWakeWord::ParseWakenetModelConfig()
{
    // Get the index.json file path from the model list
    const char *index_json_path = esp_srmodel_get_file_path(models_, "index.json");
    if (index_json_path == nullptr)
    {
        ESP_LOGE(TAG, "Failed to get index.json file path");
        return;
    }

    // Read the JSON file content
    FILE *fp = fopen(index_json_path, "r");
    if (fp == nullptr)
    {
        ESP_LOGE(TAG, "Failed to open index.json file: %s", index_json_path);
        return;
    }

    // Get file size
    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);
    fseek(fp, 0, SEEK_SET);

    // Allocate buffer for JSON content
    char *json_content = (char *)malloc(file_size + 1);
    if (json_content == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate memory for JSON content");
        fclose(fp);
        return;
    }

    // Read JSON content
    size_t bytes_read = fread(json_content, 1, file_size, fp);
    json_content[bytes_read] = '\0';
    fclose(fp);

    // Parse JSON
    cJSON *json_root = cJSON_Parse(json_content);
    if (json_root == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse JSON content");
        free(json_content);
        return;
    }

    // Parse language
    cJSON *language_obj = cJSON_GetObjectItem(json_root, "language");
    if (language_obj != nullptr && cJSON_IsString(language_obj))
    {
        language_ = cJSON_GetStringValue(language_obj);
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    }

    // Parse duration
    cJSON *duration_obj = cJSON_GetObjectItem(json_root, "duration");
    if (duration_obj != nullptr && cJSON_IsNumber(duration_obj))
    {
        duration_ = cJSON_GetNumberValue(duration_obj);
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    }

    // Parse threshold
    cJSON *threshold_obj = cJSON_GetObjectItem(json_root, "threshold");
    if (threshold_obj != nullptr && cJSON_IsNumber(threshold_obj))
    {
        threshold_ = cJSON_GetNumberValue(threshold_obj);
        ESP_LOGI(TAG, "Parsed threshold: %f", threshold_);
    }

    // Parse commands
    cJSON *commands_obj = cJSON_GetObjectItem(json_root, "commands");
    if (commands_obj != nullptr && cJSON_IsArray(commands_obj))
    {
        int num_commands = cJSON_GetArraySize(commands_obj);
        ESP_LOGI(TAG, "Found %d commands in config", num_commands);

        commands_.clear();
        for (int i = 0; i < num_commands; i++)
        {
            cJSON *command_obj = cJSON_GetArrayItem(commands_obj, i);
            if (command_obj != nullptr)
            {
                // Parse command name
                cJSON *name_obj = cJSON_GetObjectItem(command_obj, "name");
                std::string command_name = (name_obj != nullptr && cJSON_IsString(name_obj)) ? 
                                         cJSON_GetStringValue(name_obj) : "";

                // Parse display text
                cJSON *display_obj = cJSON_GetObjectItem(command_obj, "display");
                std::string display_text = (display_obj != nullptr && cJSON_IsString(display_obj)) ? 
                                         cJSON_GetStringValue(display_obj) : "";

                // Parse action
                cJSON *action_obj = cJSON_GetObjectItem(command_obj, "action");
                std::string action = (action_obj != nullptr && cJSON_IsString(action_obj)) ? 
                                   cJSON_GetStringValue(action_obj) : "";

                // Add command to list
                if (!command_name.empty())
                {
                    commands_.push_back({command_name, display_text, action});
                    ESP_LOGI(TAG, "Parsed command: name='%s', display='%s', action='%s'", 
                            command_name.c_str(), display_text.c_str(), action.c_str());
                }
            }
        }
    }

    // Clean up
    cJSON_Delete(json_root);
    free(json_content);
}

bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    codec_ = codec;

    // Parse wakenet model configuration
    ParseWakenetModelConfig();

    // Check if we have valid commands
    if (commands_.empty())
    {
        ESP_LOGE(TAG, "No commands found in configuration");
        return false;
    }

    // Find and load the multinet model
    models_ = models_list;
    if (models_ == nullptr)
    {
        ESP_LOGE(TAG, "Invalid models list");
        return false;
    }

    // Look for the multinet model in the model list
    const char *model_name = nullptr;
    for (int i = 0; i < models_->count; i++)
    {
        if (strstr(models_->list[i].name, "multinet") != nullptr)
        {
            model_name = models_->list[i].name;
            break;
        }
    }

    if (model_name == nullptr)
    {
        ESP_LOGE(TAG, "Multinet model not found in models list");
        return false;
    }

    // Initialize the multinet model
    multinet_ = esp_mn_get_interface(model_name);
    if (multinet_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to get multinet interface");
        return false;
    }

    // Create model data with specific parameters
    multinet_model_data_ = multinet_->create(model_name, language_.c_str(), duration_, threshold_);
    if (multinet_model_data_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Set up the wake word encoding task
    const size_t stack_size = 4096 * 7;
    wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
    if (wake_word_encode_task_stack_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate stack for wake word encode task");
        return false;
    }

    wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
    if (wake_word_encode_task_buffer_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return false;
    }

    // Initialize the wake word PCM storage
    wake_word_pcm_.clear();

    // Initialize the wake word OPUS storage
    wake_word_opus_.clear();

    // Set initial state
    running_ = false;

    ESP_LOGI(TAG, "Custom wake word initialized successfully");
    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (!running_ || multinet_ == nullptr || multinet_model_data_ == nullptr)
    {
        return;
    }

    // Convert stereo to mono if needed (take left channel)
    std::vector<int16_t> mono_data;
    if (data.size() % 2 == 0)
    {
        // Assume stereo input, extract left channel
        mono_data.reserve(data.size() / 2);
        for (size_t i = 0; i < data.size(); i += 2)
        {
            mono_data.push_back(data[i]);
        }
    }
    else
    {
        // Already mono or irregular, use as-is
        mono_data = data;
    }

    // Store the audio data for potential later encoding
    StoreWakeWordData(mono_data);

    // Run wake word detection
    int result = multinet_->detect(multinet_model_data_, mono_data.data());

    // Check if wake word was detected
    if (result > 0)
    {
        // Get the detected command name
        const char *command_name = multinet_->get_command_name(multinet_model_data_, result);
        if (command_name != nullptr && wake_word_detected_callback_ != nullptr)
        {
            // Trigger the callback with the detected wake word
            wake_word_detected_callback_(std::string(command_name));

            // Stop processing until reactivated
            running_ = false;
        }
    }
}

void CustomWakeWord::EncodeWakeWordData()
{
    // Create a new thread to handle encoding
    if (wake_word_encode_task_stack_ == nullptr)
    {
        wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(CONFIG_ESP_MAIN_TASK_STACK_SIZE, MALLOC_CAP_SPIRAM);
        if (wake_word_encode_task_stack_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate stack for wake word encode task");
            return;
        }
    }

    if (wake_word_encode_task_buffer_ == nullptr)
    {
        wake_word_encode_task_buffer_ = (uint8_t *)heap_caps_malloc(4096, MALLOC_CAP_SPIRAM);
        if (wake_word_encode_task_buffer_ == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate buffer for wake word encode task");
            return;
        }
    }

    // Start the encoding task
    xTaskCreatePinnedToCore(
        [](void *pvParameters)
        {
            CustomWakeWord *self = static_cast<CustomWakeWord *>(pvParameters);

            // Initialize Opus encoder
            OpusEncoder *encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
            if (encoder == NULL)
            {
                ESP_LOGE(TAG, "Failed to create Opus encoder");
                return;
            }

            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));

            // Process stored PCM data
            while (true)
            {
                {
                    std::unique_lock<std::mutex> lock(self->wake_word_mutex_);
                    if (self->wake_word_pcm_.empty())
                    {
                        lock.unlock();
                        vTaskDelay(pdMS_TO_TICKS(100)); // Wait before checking again
                        continue;
                    }

                    // Process all available PCM data
                    while (!self->wake_word_pcm_.empty())
                    {
                        auto pcm_data = self->wake_word_pcm_.front();
                        self->wake_word_pcm_.pop_front();

                        lock.unlock();

                        // Encode PCM data to Opus
                        int opus_frame_size = opus_encode(encoder, pcm_data.data(), pcm_data.size(), 
                                                          self->wake_word_encode_task_buffer_, 4096);

                        if (opus_frame_size > 0)
                        {
                            // Add encoded data to queue
                            std::unique_lock<std::mutex> lock2(self->wake_word_mutex_);
                            std::vector<uint8_t> opus_data(opus_frame_size);
                            memcpy(opus_data.data(), self->wake_word_encode_task_buffer_, opus_frame_size);
                            self->wake_word_opus_.push_back(std::move(opus_data));
                            self->wake_word_cv_.notify_one();
                        }

                        lock.lock();
                    }
                }

                // Add termination marker
                {
                    std::unique_lock<std::mutex> lock(self->wake_word_mutex_);
                    std::vector<uint8_t> termination_marker = {0x00, 0x00, 0x00, 0x00}; // Placeholder for termination marker
                    self->wake_word_opus_.push_back(std::move(termination_marker));
                    self->wake_word_cv_.notify_one();
                }

                // Clean up and exit
                opus_encoder_destroy(encoder);
                break;
            }
        },
        "wake_word_encode",
        CONFIG_ESP_MAIN_TASK_STACK_SIZE,
        this,
        5,
        NULL,
        1
    );
}

