}

std::string Board::GenerateUuid()
{
    uint8_t uuid[16];

    // Generate 16 bytes of random data
    esp_fill_random(uuid, sizeof(uuid));

    // Set the version bits (bits 12-15 of the time_hi_and_version field)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set the variant bits (bits 6-7 of the clock_seq_hi_res field)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as UUID string: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    char uuid_str[37]; // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

std::string Board::GetSystemInfoJson()
{
    // Hardware info
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    // Flash size
    size_t flash_size;
    esp_flash_get_size(NULL, &flash_size);

    // MAC address
    uint8_t mac[6];
    esp_efuse_mac_get_default(mac);

    // OTA boot partition
    const esp_partition_t* boot_partition = esp_ota_get_boot_partition();
    char ota_partition_label[16];
    if (boot_partition && boot_partition->label[0] != '\0') {
        strncpy(ota_partition_label, boot_partition->label, sizeof(ota_partition_label) - 1);
        ota_partition_label[sizeof(ota_partition_label) - 1] = '\0';
    } else {
        strcpy(ota_partition_label, "unknown");
    }

    // Free heap size
    size_t min_free_heap = esp_get_free_heap_size();

    // Constructing JSON manually
    std::string json = "{";

    // Add hardware info
    json += "\"hardware\":{";
    json += "\"chip_model\":\"ESP32\",";
    json += "\"chip_cores\":" + std::to_string(chip_info.cores) + ",";
    json += "\"chip_revision\":" + std::to_string(chip_info.revision) + ",";
    json += "\"flash_size\":" + std::to_string(flash_size) + ",";
    json += "\"mac_address\":\"" +
            std::to_string(mac[0], 16) + ":" +
            std::to_string(mac[1], 16) + ":" +
            std::to_string(mac[2], 16) + ":" +
            std::to_string(mac[3], 16) + ":" +
            std::to_string(mac[4], 16) + ":" +
            std::to_string(mac[5], 16) + "\"";
    json += "},";

    // Add app metadata
    json += "\"application\":{";
    json += "\"name\":\"" APP_NAME "\",";
    json += "\"version\":\"" APP_VERSION "\",";
    json += "\"compile_time\":\"" COMPILE_TIME "\"";
    json += "},";

    // Add partition info
    json += "\"partition\":{";
    json += "\"boot_label\":\"" + std::string(ota_partition_label) + "\"";
    json += "},";

    // Add runtime info
    json += "\"runtime\":{";
    json += "\"min_free_heap\":" + std::to_string(min_free_heap) + ",";
    json += "\"uuid\":\"" + uuid_ + "\"";
    json += "}";

    json += "}";

    return json;
}

Esp32Camera::Esp32Camera(const esp_video_init_config_t &config)
{
    video_fd_ = -1;
    streaming_on_ = false;
    sensor_format_ = 0;
    sensor_width_ = 0;
    sensor_height_ = 0;
    frame_.data = nullptr;
    frame_.len = 0;
    frame_.format = 0;

    // Log available video devices if debug mode is enabled
#if CONFIG_XIAOZHI_ENABLE_CAMERA_DEBUG_MODE
    log_available_video_devices();
#endif

    // Determine video device path based on configuration
    const char *device_path = nullptr;

    // Try to find a suitable video device based on configuration
    // This is a simplified approach - in reality this would depend on the specific sensor type
    for (int i = 0; i < 5; i++) {  // Try first 5 video devices
        char path[16];
        snprintf(path, sizeof(path), "/dev/video%d", i);

        int fd = open(path, O_RDWR);
        if (fd >= 0) {
            device_path = path;
            video_fd_ = fd;
            break;
        }
    }

    if (video_fd_ < 0) {
        ESP_LOGE(TAG, "Failed to open any video device");
        return;
    }

    // Query device capabilities
    struct v4l2_capability cap = {};
    if (ioctl(video_fd_, VIDIOC_QUERYCAP, &cap) != 0) {
        ESP_LOGE(TAG, "VIDIOC_QUERYCAP failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Check if device supports video capture
    if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
        ESP_LOGE(TAG, "Video device does not support video capture");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Set pixel format and resolution from config
    struct v4l2_format fmt = {};
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;

    // Set format based on config
    fmt.fmt.pix.width = config.width;
    fmt.fmt.pix.height = config.height;
    fmt.fmt.pix.pixelformat = config.pixel_format;
    fmt.fmt.pix.field = V4L2_FIELD_INTERLACED;

    if (ioctl(video_fd_, VIDIOC_S_FMT, &fmt) != 0) {
        ESP_LOGE(TAG, "VIDIOC_S_FMT failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Store actual format settings
    sensor_format_ = fmt.fmt.pix.pixelformat;
    sensor_width_ = fmt.fmt.pix.width;
    sensor_height_ = fmt.fmt.pix.height;

    // Print format information if debug is enabled
#if CONFIG_XIAOZHI_ENABLE_CAMERA_DEBUG_MODE
    CAM_PRINT_FOURCC(fmt.fmt.pix.pixelformat);
    ESP_LOGD(TAG, "Resolution: %dx%d", fmt.fmt.pix.width, fmt.fmt.pix.height);
#endif

    // Request memory mapping buffers
    struct v4l2_requestbuffers req = {};
    req.count = 4;
    req.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    req.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_REQBUFS, &req) != 0) {
        ESP_LOGE(TAG, "VIDIOC_REQBUFS failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    if (req.count < 2) {
        ESP_LOGE(TAG, "Insufficient buffer memory");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Map buffers
    mmap_buffers_.resize(req.count);
    for (int i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QUERYBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QUERYBUF failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }

        mmap_buffers_[i].start = mmap(NULL, buf.length, PROT_READ | PROT_WRITE, MAP_SHARED, video_fd_, buf.m.offset);
        mmap_buffers_[i].length = buf.length;

        if (mmap_buffers_[i].start == MAP_FAILED) {
            ESP_LOGE(TAG, "mmap failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }
    }

    // Queue all buffers
    for (int i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }
    }

    // Start streaming
    int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(video_fd_, VIDIOC_STREAMON, &type) != 0) {
        ESP_LOGE(TAG, "VIDIOC_STREAMON failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    streaming_on_ = true;

    // Initialize frame structure
    frame_.width = sensor_width_;
    frame_.height = sensor_height_;

    ESP_LOGI(TAG, "Camera initialized successfully: %dx%d, format: 0x%08lx", 
             sensor_width_, sensor_height_, sensor_format_);
}

bool Esp32Camera::Capture()
{
    if (video_fd_ < 0 || !streaming_on_)
    {
        ESP_LOGE(TAG, "Camera not initialized or streaming not active");
        return false;
    }

    struct v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;

    // Dequeue buffer
    if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_DQBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    // Check if we have valid buffer
    if (buf.index >= mmap_buffers_.size())
    {
        ESP_LOGE(TAG, "Invalid buffer index: %u", buf.index);
        // Requeue the buffer before returning
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
        {
            ESP_LOGE(TAG, "Failed to requeue buffer, errno=%d(%s)", errno, strerror(errno));
        }
        return false;
    }

    // Get buffer info
    auto &buffer_info = mmap_buffers_[buf.index];

    // Copy frame data to our frame structure
    // Allocate memory for frame data
    if (frame_.data)
    {
        heap_caps_free(frame_.data);
        frame_.data = nullptr;
    }

    // Calculate frame size based on pixel format
    size_t frame_size = buf.bytesused;
    if (frame_size == 0)
    {
        frame_size = buffer_info.length;
    }

    // Allocate memory in PSRAM if available, otherwise regular RAM
    frame_.data = (uint8_t *)heap_caps_malloc(frame_size, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
    if (frame_.data == nullptr)
    {
        ESP_LOGW(TAG, "Failed to allocate PSRAM for frame, trying regular RAM");
        frame_.data = (uint8_t *)malloc(frame_size);
        if (frame_.data == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate memory for frame");
            // Requeue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
            {
                ESP_LOGE(TAG, "Failed to requeue buffer, errno=%d(%s)", errno, strerror(errno));
            }
            return false;
        }
    }

    // Copy frame data
    memcpy(frame_.data, buffer_info.start, frame_size);
    frame_.len = frame_size;
    frame_.format = sensor_format_;

#ifdef CONFIG_XIAOZHI_ENABLE_ROTATE_CAMERA_IMAGE
    // Apply rotation if needed
    if (sensor_format_ != V4L2_PIX_FMT_JPEG)
    {
        uint8_t *rotated_data = nullptr;
        size_t rotated_len = 0;

        // Use PPA for ESP32-P4 or software rotation for other targets
#ifdef CONFIG_IDF_TARGET_ESP32P4
        // PPA-based rotation
        ppa_srm_config_t srm_cfg = {};
        srm_cfg.src_addr = frame_.data;
        srm_cfg.dst_addr = nullptr; // Will be allocated by PPA
        srm_cfg.src_w = sensor_width_;
        srm_cfg.src_h = sensor_height_;
        srm_cfg.dst_w = frame_.width;
        srm_cfg.dst_h = frame_.height;
        srm_cfg.rotation = IMAGE_ROTATION_ANGLE;
        srm_cfg.pixel_format = sensor_format_;

        if (ppa_srm_process(&srm_cfg, &rotated_data, &rotated_len) == ESP_OK)
        {
            // Free original data and update frame
            heap_caps_free(frame_.data);
            frame_.data = rotated_data;
            frame_.len = rotated_len;
        }
        else
        {
            ESP_LOGE(TAG, "PPA rotation failed");
        }
#else
        // Software rotation
        rotated_data = (uint8_t *)heap_caps_malloc(frame_.len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
        if (rotated_data != nullptr)
        {
            if (esp_imgfx_rotate(frame_.data, frame_.len, sensor_width_, sensor_height_, 
                               IMAGE_ROTATION_ANGLE, rotated_data, &rotated_len, sensor_format_) == ESP_OK)
            {
                // Free original data and update frame
                heap_caps_free(frame_.data);
                frame_.data = rotated_data;
                frame_.len = rotated_len;
            }
            else
            {
                ESP_LOGE(TAG, "Software rotation failed");
                heap_caps_free(rotated_data);
            }
        }
#endif
    }
#endif

    // Requeue buffer for reuse
    if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_QBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    return true;
}

std::string Esp32Camera::Explain(const std::string &question)
{
    if (explain_url_.empty()) {
        ESP_LOGE(TAG, "Explain URL not set, call SetExplainUrl() first");
        return R"({"success": false, "message": "Explain URL not configured"})";
    }

    // Capture a frame
    if (!Capture()) {
        ESP_LOGE(TAG, "Failed to capture frame for explanation");
        return R"({"success": false, "message": "Failed to capture frame"})";
    }

    // Check if we have valid frame data
    if (!frame_.data || frame_.len == 0) {
        ESP_LOGE(TAG, "Frame data is empty");
        return R"({"success": false, "message": "No frame data available"})";
    }

    // Prepare JPEG encoding parameters
    esp_jpeg_encode_cfg_t encode_cfg = {
        .in_frame = {
            .width = frame_.width,
            .height = frame_.height,
            .pixel_format = ESP_JPEG_PIXEL_FORMAT_RGB565,
        },
        .quality = 80,
        .output_format = ESP_JPEG_OUTPUT_FORMAT_JPEG,
    };

    // Convert frame format if needed
    uint8_t *jpeg_data = nullptr;
    size_t jpeg_len = 0;

    // If frame is already RGB565, we can directly encode it
    if (frame_.format == V4L2_PIX_FMT_RGB565) {
        encode_cfg.in_frame.pixel_format = ESP_JPEG_PIXEL_FORMAT_RGB565;
    } else if (frame_.format == V4L2_PIX_FMT_YUYV || frame_.format == V4L2_PIX_FMT_YUV420) {
        // Convert to RGB565 first
        uint8_t *rgb565_data = (uint8_t *)heap_caps_malloc(frame_.width * frame_.height * 2, 
                                                           MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
        if (!rgb565_data) {
            ESP_LOGE(TAG, "Failed to allocate memory for RGB565 conversion");
            return R"({"success": false, "message": "Memory allocation failed"})";
        }

        esp_imgfx_color_convert_cfg_t convert_cfg = {
            .in_res = {.width = static_cast<int16_t>(frame_.width),
                       .height = static_cast<int16_t>(frame_.height)},
            .in_pixel_fmt = static_cast<esp_imgfx_pixel_fmt_t>(frame_.format),
            .out_pixel_fmt = ESP_IMGFX_PIXEL_FMT_RGB565_LE,
        };

        esp_imgfx_color_convert_handle_t convert_handle = nullptr;
        esp_imgfx_err_t err = esp_imgfx_color_convert_open(&convert_cfg, &convert_handle);
        if (err != ESP_IMGFX_ERR_OK || convert_handle == nullptr) {
            ESP_LOGE(TAG, "Failed to open color convert handle");
            heap_caps_free(rgb565_data);
            return R"({"success": false, "message": "Color conversion failed"})";
        }

        esp_imgfx_data_t convert_input_data = {
            .data = frame_.data,
            .data_len = frame_.len,
        };
        esp_imgfx_data_t convert_output_data = {
            .data = rgb565_data,
            .data_len = static_cast<uint32_t>(frame_.width * frame_.height * 2),
        };

        err = esp_imgfx_color_convert_process(convert_handle, &convert_input_data, &convert_output_data);
        esp_imgfx_color_convert_close(convert_handle);

        if (err != ESP_IMGFX_ERR_OK) {
            ESP_LOGE(TAG, "Color conversion process failed");
            heap_caps_free(rgb565_data);
            return R"({"success": false, "message": "Color conversion failed"})";
        }

        // Now encode the RGB565 data
        encode_cfg.in_frame.pixel_format = ESP_JPEG_PIXEL_FORMAT_RGB565;
        encode_cfg.in_frame.data = rgb565_data;
        encode_cfg.in_frame.data_len = frame_.width * frame_.height * 2;

        // Encode to JPEG
        esp_err_t ret = esp_jpeg_encode(&encode_cfg, &jpeg_data, &jpeg_len);
        heap_caps_free(rgb565_data);

        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "JPEG encoding failed: %d", ret);
            return R"({"success": false, "message": "JPEG encoding failed"})";
        }
    } else {
        // For RGB565 directly
        encode_cfg.in_frame.pixel_format = ESP_JPEG_PIXEL_FORMAT_RGB565;
        encode_cfg.in_frame.data = frame_.data;
        encode_cfg.in_frame.data_len = frame_.len;

        // Encode to JPEG
        esp_err_t ret = esp_jpeg_encode(&encode_cfg, &jpeg_data, &jpeg_len);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "JPEG encoding failed: %d", ret);
            return R"({"success": false, "message": "JPEG encoding failed"})";
        }
    }

    // Create HTTP request
    std::string boundary = "----WebKitFormBoundary7MA4YWxkTrZu0gW";
    std::string content_type = "multipart/form-data; boundary=" + boundary;

    // Build multipart form data
    std::string form_data = "--" + boundary + "\r\n";
    form_data += "Content-Disposition: form-data; name=\"image\"; filename=\"image.jpg\"\r\n";
    form_data += "Content-Type: image/jpeg\r\n\r\n";

    // Add JPEG data
    form_data.append((char*)jpeg_data, jpeg_len);
    form_data += "\r\n--" + boundary + "\r\n";
    form_data += "Content-Disposition: form-data; name=\"question\"\r\n\r\n";
    form_data += question;
    form_data += "\r\n--" + boundary + "--\r\n";

    // Send HTTP POST request
    std::string response = "";
    esp_err_t http_ret = mcp_server_http_post(explain_url_, content_type, form_data, response);

    // Free JPEG data
    if (jpeg_data) {
        heap_caps_free(jpeg_data);
    }

    if (http_ret != ESP_OK) {
        ESP_LOGE(TAG, "HTTP POST failed: %d", http_ret);
        return R"({"success": false, "message": "HTTP request failed"})";
    }

    // Return the server response
    return response;
}

void WifiBoard::StartNetwork()
{
    // Set up unified event callback for WiFi events
    WifiManager::GetInstance().SetEventCallback([this](NetworkEvent event, const std::string &data) {
        OnNetworkEvent(event, data);
    });

    // Initialize WiFi manager with predefined SSID prefix and language
    // This would typically involve setting up the WiFi configuration
    // The actual initialization is handled by the WifiManager class

    // Attempt to connect to WiFi
    TryWifiConnect();
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    // Notify external callback if set
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }

    switch (event) {
        case NetworkEvent::Connecting:
            // Stop any existing connection timer
            esp_timer_stop(connect_timer_);
            break;

        case NetworkEvent::Connected:
            // Stop connection timer when connected
            esp_timer_stop(connect_timer_);

            // Reset config mode flag
            in_config_mode_ = false;

            // Update device state
            Application::GetInstance().SetDeviceState(kDeviceStateIdle);

            // Release provisioning resources if needed
            // (This would typically be handled by the WifiManager itself)
            break;

        case NetworkEvent::Disconnected:
            // Stop connection timer
            esp_timer_stop(connect_timer_);

            // If we were in config mode, don't reconnect automatically
            if (!in_config_mode_) {
                // Restart connection attempt with timeout
                ESP_LOGI(TAG, "WiFi disconnected, attempting reconnection");
                esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
                WifiManager::GetInstance().StartStation();
            }
            break;

        case NetworkEvent::Scanning:
            // No specific action needed for scanning
            break;

        case NetworkEvent::WifiConfigModeEnter:
            // We're already in config mode, just update state
            in_config_mode_ = true;
            break;

        case NetworkEvent::WifiConfigModeExit:
            // Exit config mode and attempt to reconnect
            in_config_mode_ = false;

            // Restart connection attempt with timeout
            ESP_LOGI(TAG, "Exiting WiFi config mode, attempting reconnection");
            esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
            WifiManager::GetInstance().StartStation();
            break;
    }
}

void WifiBoard::StartWifiConfigMode()
{
    // Set device state to configuring mode
    auto &app = Application::GetInstance();
    app.SetDeviceState(kDeviceStateConfiguring);

    // Show notification to user
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_NOTIFICATION);

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Start BLUFI provisioning if enabled
    ESP_LOGI(TAG, "Starting BLUFI provisioning");
    Blufi::GetInstance().init();
    Blufi::GetInstance().start();
#else
    // Fallback to hotspot-based configuration
    ESP_LOGI(TAG, "Starting hotspot-based configuration");

    // Configure WiFi in AP mode for hotspot
    WifiManagerConfig config;
    config.ssid_prefix = "Xiaozhi-Config";
    config.language = Lang::CODE;
    WifiManager::GetInstance().Initialize(config);

    // Start access point mode
    WifiManager::GetInstance().StartAccessPoint();
#endif

    // Update network state icon
    GetDisplay()->UpdateNetworkStateIcon();
}

void WifiBoard::EnterWifiConfigMode()
{
    // Stop any ongoing WiFi connection attempts
    WifiManager::GetInstance().StopStation();

    // Stop timeout timer if running
    esp_timer_stop(connect_timer_);

    // Reset any active audio/communication processes
    auto &app = Application::GetInstance();
    auto &board = Board::GetInstance();

    // Stop any ongoing audio playback or recording
    if (auto codec = board.GetAudioCodec()) {
        codec->stop();
    }

    // Stop any ongoing network operations
    WifiManager::GetInstance().StopStation();

    // Enter Wi-Fi configuration mode
    StartWifiConfigMode();
}

std::string WifiBoard::GetDeviceStatusJson()
{
    auto &wifi = WifiManager::GetInstance();
    auto &audio = Board::GetInstance().GetAudioCodec();
    auto &display = Board::GetInstance().GetDisplay();
    auto &power = PowerManager::GetInstance();

    std::string json = "{";

    // Audio speaker volume
    if (audio) {
        json += "\"volume\":" + std::to_string(audio->volume()) + ",";
    } else {
        json += "\"volume\":0,";
    }

    // Screen brightness and theme
    if (display) {
        json += "\"brightness\":" + std::to_string(display->brightness()) + ",";
        json += "\"theme\":\"" + display->theme() + "\",";
    } else {
        json += "\"brightness\":0,\"theme\":\"default\",";
    }

    // Battery level and charging state
    json += "\"battery\":" + std::to_string(power.GetBatteryLevel()) + ",";
    json += "\"charging\":" + std::to_string(power.IsCharging() ? 1 : 0) + ",";

    // WiFi network details
    if (!wifi.IsConfigMode()) {
        json += "\"ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"rssi\":" + std::to_string(wifi.GetRssi()) + ",";
    } else {
        json += "\"ssid\":\"\",\"rssi\":0,";
    }

    // Chip temperature
    json += "\"temperature\":" + std::to_string(SystemInfo::GetChipTemperature()) + ",";

    // Remove trailing comma and close JSON
    if (json.back() == ',') {
        json.pop_back();
    }
    json += "}";

    return json;
}

