#if CONFIG_IDF_TARGET_ESP32P4
#define MAX_MESSAGES 40
#else
#define MAX_MESSAGES 20
#endif
void LcdDisplay::SetChatMessage(const char *role, const char *content)
{
    DisplayLockGuard lock(this);

    if (content_ == nullptr || content == nullptr) {
        return;
    }

    // Don't display empty messages
    if (strlen(content) == 0) {
        return;
    }

    // Hide the AI logo when showing non-system messages
    if (emoji_label_ != nullptr && strcmp(role, "system") != 0) {
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
    }

    // Create a message bubble based on role
    lv_obj_t *msg_bubble = lv_obj_create(content_);
    lv_obj_set_style_radius(msg_bubble, 8, 0);
    lv_obj_set_scrollbar_mode(msg_bubble, LV_SCROLLBAR_MODE_OFF);
    lv_obj_set_style_border_width(msg_bubble, 0, 0);
    lv_obj_set_style_pad_all(msg_bubble, 8, 0);

    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);

    // Set bubble background color based on role
    if (strcmp(role, "user") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->user_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"user");
    } else if (strcmp(role, "assistant") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->assistant_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"assistant");
    } else if (strcmp(role, "system") == 0) {
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->system_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"system");
    } else {
        // Default to assistant style for unknown roles
        lv_obj_set_style_bg_color(msg_bubble, lvgl_theme->assistant_bubble_color(), 0);
        lv_obj_set_style_bg_opa(msg_bubble, LV_OPA_70, 0);
        lv_obj_set_user_data(msg_bubble, (void *)"assistant");
    }

    // Set border color
    lv_obj_set_style_border_color(msg_bubble, lvgl_theme->border_color(), 0);

    // Create label inside bubble for message text
    lv_obj_t *msg_label = lv_label_create(msg_bubble);
    lv_label_set_text(msg_label, content);
    lv_obj_set_width(msg_label, LV_HOR_RES * 70 / 100); // Limit width to 70% of screen

    // Set text color based on role
    if (strcmp(role, "system") == 0) {
        lv_obj_set_style_text_color(msg_label, lvgl_theme->system_text_color(), 0);
    } else {
        lv_obj_set_style_text_color(msg_label, lvgl_theme->text_color(), 0);
    }

    // Set text alignment
    lv_label_set_long_mode(msg_label, LV_LABEL_LONG_WRAP);
    lv_obj_set_style_text_align(msg_label, LV_TEXT_ALIGN_LEFT, 0);

    // Set bubble size and positioning
    lv_obj_set_style_flex_grow(msg_bubble, 0, 0);

    // Position based on role
    if (strcmp(role, "user") == 0) {
        lv_obj_align(msg_bubble, LV_ALIGN_RIGHT_MID, 0, 0);
    } else {
        lv_obj_align(msg_bubble, LV_ALIGN_LEFT_MID, 0, 0);
    }

    // Auto-scroll to the new message
    lv_obj_scroll_to_view_recursive(msg_bubble, LV_ANIM_ON);

    // Manage message history - remove oldest messages if needed
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    if (child_count > MAX_MESSAGES) {
        // Remove the oldest message (first child)
        lv_obj_t *oldest_msg = lv_obj_get_child(content_, 0);
        if (oldest_msg != nullptr) {
            lv_obj_del(oldest_msg);
        }
    }
}

void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image)
{
    DisplayLockGuard lock(this);
    if (preview_image_ == nullptr)
    {
        ESP_LOGE(TAG, "Preview image is not initialized");
        return;
    }

    if (image == nullptr)
    {
        esp_timer_stop(preview_timer_);
        lv_obj_remove_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
        lv_obj_add_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
        preview_image_cached_.reset();
        if (gif_controller_)
        {
            gif_controller_->Start();
        }
        return;
    }

    preview_image_cached_ = std::move(image);
    auto img_dsc = preview_image_cached_->image_dsc();
    lv_image_set_src(preview_image_, img_dsc);
    if (img_dsc->header.w > 0 && img_dsc->header.h > 0)
    {
        // zoom factor 0.5
        lv_image_set_scale(preview_image_, 128 * width_ / img_dsc->header.w);
    }

    // Hide emoji_box_
    if (gif_controller_)
    {
        gif_controller_->Stop();
    }
    lv_obj_add_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
    lv_obj_remove_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
    esp_timer_stop(preview_timer_);
    ESP_ERROR_CHECK(esp_timer_start_once(preview_timer_, PREVIEW_IMAGE_DURATION_MS * 1000));
}

